"use strict";(self.webpackChunktechdocs=self.webpackChunktechdocs||[]).push([[9585],{943:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>d,contentTitle:()=>r,default:()=>l,frontMatter:()=>s,metadata:()=>a,toc:()=>h});var a=n(5811),i=n(4848),o=n(8453);const s={title:"What is an MCP server and why does it need documentation?",slug:"what-is-an-mcp-server",description:"Most teams shipping AI products are not documenting the MCP layer that connects the model to everything else. Here is why that matters and what to do about it.",tags:["mcp","documentation","ai","fintech","product-management","technical-writing"],authors:["ivanwalsh"],date:new Date("2026-04-04T00:00:00.000Z")},r=void 0,d={authorsImageUrls:[void 0]},h=[{value:"Where technical writers fit in",id:"where-technical-writers-fit-in",level:2},{value:"A note for Product Managers",id:"a-note-for-product-managers",level:2},{value:"What an MCP server actually is",id:"what-an-mcp-server-actually-is",level:2},{value:"Why MCP documentation is harder than API documentation",id:"why-mcp-documentation-is-harder-than-api-documentation",level:2},{value:"The five things every MCP server document needs",id:"the-five-things-every-mcp-server-document-needs",level:2},{value:"A note for financial services teams",id:"a-note-for-financial-services-teams",level:2},{value:"Do this today",id:"do-this-today",level:2}];function c(e){const t={a:"a",code:"code",h2:"h2",li:"li",p:"p",strong:"strong",ul:"ul",...(0,o.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.p,{children:"Most teams shipping AI products in 2026 are focused on the model. Which one to use, how to fine-tune it, how to evaluate its outputs. What they are not focused on, almost universally, is the layer that connects the model to everything else."}),"\n",(0,i.jsx)(t.p,{children:"That layer is the MCP server. And almost nobody is documenting it."}),"\n",(0,i.jsx)(t.p,{children:"This is a problem. Not an inconvenience but a genuine technical risk, and in regulated industries, a compliance risk too. A developer joining a project finds an MCP server in the codebase with no tool reference, no input schema, no error documentation. The model is using it. Nobody knows exactly how. The person who built it left six months ago."}),"\n",(0,i.jsx)(t.h2,{id:"where-technical-writers-fit-in",children:"Where technical writers fit in"}),"\n",(0,i.jsx)(t.p,{children:"Here is what makes this problem different from every other documentation gap in software development: by the time a technical writer is typically brought in, it is too late."}),"\n",(0,i.jsx)(t.p,{children:"In most software projects, documentation happens after the build. A writer gets access to a finished product, interviews the developers, and works backwards to produce something useful. This approach is imperfect but workable for conventional software. The product does not change its behaviour based on what the writer produces."}),"\n",(0,i.jsx)(t.p,{children:"MCP servers break this model entirely. The documentation is not a description of how the system works. It is an input to how the system works. The tool descriptions, the input schemas, the parameter constraints are all read by the AI model at runtime and directly shape its behaviour. If a technical writer reviews a finished MCP server and finds the descriptions vague, rewriting them is not a documentation task. It is a product change."}),"\n",(0,i.jsx)(t.p,{children:"This means technical writers need to be involved during development, not after it. Specifically, they need to be in the room when tool schemas are being defined, asking the questions the AI model will implicitly need answered. What does this tool do in plain terms? What happens when this parameter is missing? What does a valid response look like when the upstream system is unavailable?"}),"\n",(0,i.jsx)(t.p,{children:"These are documentation questions. They are also product design questions. A technical writer who understands MCP is doing both simultaneously."}),"\n",(0,i.jsx)(t.h2,{id:"a-note-for-product-managers",children:"A note for Product Managers"}),"\n",(0,i.jsx)(t.p,{children:"If you are a Product Manager delivering AI products, the Definition of Done for any user story that involves an MCP server should include documentation sign-off. Not as a checkbox, but as a quality gate."}),"\n",(0,i.jsx)(t.p,{children:"Specifically, the DoD should require:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Every tool exposed by the MCP server has a description precise enough for the AI model to select it correctly"}),"\n",(0,i.jsx)(t.li,{children:"Every input parameter has a documented type, requirement status, valid range, and null behaviour"}),"\n",(0,i.jsx)(t.li,{children:"Every error code has a documented meaning and expected handling path"}),"\n",(0,i.jsx)(t.li,{children:"A worked example exists for every tool, showing a realistic input and expected output"}),"\n",(0,i.jsx)(t.li,{children:"Authentication and permission requirements are documented explicitly, not assumed"}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"The rationale is simple. A user story that ships an undocumented MCP tool is not done. The model's behaviour with that tool is undefined. In regulated industries, that unpredictability carries a compliance cost that typically exceeds the cost of writing the documentation in the first place."}),"\n",(0,i.jsx)(t.p,{children:"Treat MCP documentation the same way you treat automated tests. Not something that happens after the sprint, but something that gates the story closing."}),"\n",(0,i.jsx)(t.h2,{id:"what-an-mcp-server-actually-is",children:"What an MCP server actually is"}),"\n",(0,i.jsx)(t.p,{children:"MCP stands for Model Context Protocol, an open standard developed by Anthropic that defines how AI models communicate with external tools, data sources, and services."}),"\n",(0,i.jsx)(t.p,{children:"An MCP server is a program that implements this protocol. It exposes a set of capabilities that an AI model can discover and use at runtime. Think of it as the bridge between an AI system and the outside world, the thing that lets a model check a database, call an API, read a file, or trigger an action in another system."}),"\n",(0,i.jsx)(t.p,{children:"If a REST API is a waiter who takes your order and brings food, an MCP server is a waiter who also reads the menu aloud, tells the AI which dishes are available today, and describes each one in enough detail for the AI to decide what to order."}),"\n",(0,i.jsx)(t.p,{children:"An MCP server exposes three types of primitives:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Tools: actions the AI can take, such as calling an API, running a calculation, or submitting a form"}),"\n",(0,i.jsx)(t.li,{children:"Resources: data the AI can read, such as files, database records, or live feeds"}),"\n",(0,i.jsx)(t.li,{children:"Prompts: reusable templates the AI can invoke for structured tasks"}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"Each of these needs to be documented. But the way they need to be documented is different from anything most technical writers have encountered before."}),"\n",(0,i.jsx)(t.h2,{id:"why-mcp-documentation-is-harder-than-api-documentation",children:"Why MCP documentation is harder than API documentation"}),"\n",(0,i.jsx)(t.p,{children:"When you document a REST API, your primary reader is a developer. A developer can read the docs, ask a question on Slack, experiment in Postman, and iterate until something works. The documentation is a starting point, not the final word."}),"\n",(0,i.jsx)(t.p,{children:"When you document an MCP server, your primary reader is an AI model."}),"\n",(0,i.jsx)(t.p,{children:"The model cannot ask questions. It cannot experiment. It reads the tool schema at runtime and makes decisions based entirely on what is written there. If the description is vague, the model picks the wrong tool. If the input schema is incomplete, the model formats the request incorrectly. If error codes are undocumented, the model cannot handle failures gracefully."}),"\n",(0,i.jsx)(t.p,{children:"None of this produces an obvious error. The model does not throw an exception when it misunderstands a tool description. It simply behaves incorrectly, and the root cause is documentation quality, not model capability."}),"\n",(0,i.jsx)(t.p,{children:"This reframes what documentation means in an AI system. The description field in an MCP tool schema is not metadata. It is a runtime instruction. Writing it poorly has direct consequences for how the product behaves."}),"\n",(0,i.jsx)(t.p,{children:"In regulated industries, those consequences can extend beyond bad user experience into compliance exposure. A tool that processes a transaction without a clearly documented permission model is not just a documentation gap. It is an audit gap."}),"\n",(0,i.jsx)(t.h2,{id:"the-five-things-every-mcp-server-document-needs",children:"The five things every MCP server document needs"}),"\n",(0,i.jsx)(t.p,{children:"Based on working with AI systems in regulated financial environments, there are five components that every MCP server document needs to contain."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"1. Tool inventory."})," A complete list of every tool the server exposes, with a one-line description of what each one does. This is the table of contents for the AI model, the first thing it reads to understand what is available."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"2. Input schema per tool."})," Every parameter, its type, whether it is required, and what a valid value looks like. Include edge cases. What happens if a parameter is null? What is the valid range for a numeric field? A schema that says ",(0,i.jsx)(t.code,{children:"amount: number"})," is not sufficient. ",(0,i.jsx)(t.code,{children:"amount: number, required, minimum 0, maximum 10,000,000, GBP value"})," is."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"3. Output schema per tool."})," What the tool returns on success, what it returns on failure, and what each error code means. AI models need to interpret responses, not just send requests. Undocumented error codes produce silent failures where the model receives an unexpected response and has no documented path for handling it."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"4. Authentication and permissions."})," How the server authenticates requests, and which tools require which permission levels. This section is often omitted from internal MCP servers on the assumption that everyone already knows. In financial services, the permission model for an AI tool frequently has direct regulatory implications, so assuming prior knowledge is not an option."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"5. Usage examples."})," At least one worked example per tool: a realistic input and the expected output. This is the section AI models use most heavily during inference. A concrete example anchors the abstract schema to real-world use and significantly reduces the likelihood of malformed requests."]}),"\n",(0,i.jsx)(t.h2,{id:"a-note-for-financial-services-teams",children:"A note for financial services teams"}),"\n",(0,i.jsx)(t.p,{children:"The five components above apply to any MCP server, but in financial services each one carries additional weight. A tool description that omits a rate-limiting clause can produce behaviour that breaches a trading rule. An undocumented error code can create a gap in an audit trail. Documentation in this context is part of the control framework, not an afterthought."}),"\n",(0,i.jsx)(t.h2,{id:"do-this-today",children:"Do this today"}),"\n",(0,i.jsx)(t.p,{children:"If your team has built an MCP server, do one thing before the end of the week. Open the server code and count how many tools it exposes. Then open the documentation, whatever exists, and check whether each tool has a description, a complete input schema, a documented output, and at least one worked example."}),"\n",(0,i.jsx)(t.p,{children:"In most teams, the answer will be that some tools are partially documented and several have nothing at all. That gap is not a documentation backlog. It is an active risk to product quality, to developer onboarding, and in regulated environments, to compliance."}),"\n",(0,i.jsx)(t.p,{children:"If you are a technical writer, use that audit as the basis for a conversation with your engineering and product leads this week. Bring the list of undocumented tools and a proposed documentation standard. Frame it not as a writing task but as a product quality issue, because that is what it is."}),"\n",(0,i.jsx)(t.p,{children:"If you are a Product Manager, add MCP documentation to your Definition of Done before the next sprint starts. One line in the DoD now prevents weeks of remediation later."}),"\n",(0,i.jsx)(t.p,{children:"If you are an engineering lead, block half a day in the next sprint to work through the tool inventory with your technical writer present. The output should be an agreed documentation standard for every MCP tool your team ships, established before anyone writes another line of schema code."}),"\n",(0,i.jsx)(t.p,{children:"The teams that get this right now will have a significant operational advantage over those who treat documentation as something to sort out later. In AI product development, later rarely arrives."}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"About the author"})}),"\n",(0,i.jsx)(t.p,{children:"Ivan Walsh is a Technical Writer based in Dublin, Ireland, specialising in AI-ready documentation for regulated financial platforms. He works with global financial institutions on API documentation, RAG-ready content, and chatbot integration guides for systems where precision and compliance are non-negotiable."}),"\n",(0,i.jsxs)(t.p,{children:["Connect with Ivan on ",(0,i.jsx)(t.a,{href:"https://www.linkedin.com/in/ivanwalsh/",children:"LinkedIn"})]})]})}function l(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},5811:e=>{e.exports=JSON.parse('{"permalink":"/blog/what-is-an-mcp-server","source":"@site/blog/2026-04-05-mcp-server-documentation.md","title":"What is an MCP server and why does it need documentation?","description":"Most teams shipping AI products are not documenting the MCP layer that connects the model to everything else. Here is why that matters and what to do about it.","date":"2026-04-04T00:00:00.000Z","tags":[{"inline":false,"label":"MCP","permalink":"/blog/tags/mcp","description":"Posts related to Model Context Protocol and MCP servers."},{"inline":false,"label":"Documentation","permalink":"/blog/tags/documentation","description":"Posts about documentation practices and technical writing."},{"inline":false,"label":"AI","permalink":"/blog/tags/ai","description":"Posts related to Artificial Intelligence."},{"inline":false,"label":"FinTech","permalink":"/blog/tags/fintech","description":"Posts related to financial technology and regulated financial services."},{"inline":false,"label":"Product Management","permalink":"/blog/tags/product-management","description":"Posts about product management for technical and AI products."},{"inline":false,"label":"Technical Writing","permalink":"/blog/tags/technical-writing","description":"Posts about technical writing and documentation strategy."}],"readingTime":8.3,"hasTruncateMarker":true,"authors":[{"name":"Ivan Walsh","title":"Technical Writer","url":"https://github.com/ivanwalsh","page":{"permalink":"/blog/authors/ivanwalsh"},"socials":{"x":"https://x.com/ivanwalsh","github":"https://github.com/ivanwalsh","linkedin":"https://www.linkedin.com/in/ivanwalsh/"},"imageURL":"https://github.com/ivanwalsh.png","key":"ivanwalsh"}],"frontMatter":{"title":"What is an MCP server and why does it need documentation?","slug":"what-is-an-mcp-server","description":"Most teams shipping AI products are not documenting the MCP layer that connects the model to everything else. Here is why that matters and what to do about it.","tags":["mcp","documentation","ai","fintech","product-management","technical-writing"],"authors":["ivanwalsh"],"date":"2026-04-04T00:00:00.000Z"},"unlisted":false,"nextItem":{"title":"The Human Task","permalink":"/blog/human-task"}}')},8453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>r});var a=n(6540);const i={},o=a.createContext(i);function s(e){const t=a.useContext(o);return a.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),a.createElement(o.Provider,{value:t},e.children)}}}]);